"use strict";const interpreterPath=t=>{if(t.length<64||t.readUInt32BE(0)!==2135247942||t.readUInt8(4)!==2||t.readUInt8(5)!==1)return null;const s=t.readUInt32LE(32),u=t.readUInt16LE(54),a=t.readUInt16LE(56);for(let n=0;n<a;n++){const r=s+n*u;if(t.readUInt32LE(r)===3){const e=t.readUInt32LE(r+8),o=t.readUInt32LE(r+32);return t.subarray(e,e+o).toString().replace(/\0.*$/g,"")}}return null};module.exports={interpreterPath};
